  8	import {
  9	  ProviderModelGroupVersionKind,
 10	  ProviderModelRef,
 11	  type V1beta1Provider,
 12	} from '@kubev2v/types';
 13	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 14	import {
 15	  EmptyState,
 16	  EmptyStateVariant,
 17	  Icon,
 18	  SelectList,
 19	  SelectOption,
 20	} from '@patternfly/react-core';
 21	import { ProviderCreateSource, TELEMETRY_EVENTS } from '@utils/analytics/constants';
 22	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 23	import { getName } from '@utils/crds/common/selectors';
 24	import { isEmpty } from '@utils/helpers';
 25	import { useIsDarkTheme } from '@utils/hooks/useIsDarkTheme';
 26	import { ForkliftTrans } from '@utils/i18n';
 27	import { ProviderStatus } from '@utils/types';
 28	
 29	type ProviderSelectProps = Pick<
 30	  ComponentProps<typeof Select>,
 31	  'onSelect' | 'status' | 'isDisabled'
 32	> & {
 33	  id: string;
 34	  value: string;
 35	  namespace: string | undefined;
 36	  placeholder?: string;
 37	  emptyState?: ReactNode;
 38	  isTarget?: boolean;
 39	  testId?: string;
 40	};
 41	
 42	const ProviderSelect = (
 43	  {
 44	    emptyState,
 45	    id,
 46	    isDisabled,
 47	    isTarget,
 48	    namespace,
 49	    onSelect,
 50	    placeholder,
 51	    status,
 52	    testId,
 53	    value,
 54	  }: ProviderSelectProps,
 55	  ref: ForwardedRef<HTMLButtonElement>,
 56	) => {
 57	  const isDarkTheme = useIsDarkTheme();
 58	  const { trackEvent } = useForkliftAnalytics();
 59	  const [providers] = useK8sWatchResource<V1beta1Provider[]>({
 60	    groupVersionKind: ProviderModelGroupVersionKind,
 61	    isList: true,
 62	    namespace,
 63	    namespaced: true,
 64	  });
 65	  const filteredProviders = useMemo(
 66	    () =>
 67	      providers.filter((provider) => {
 68	        const isReady = provider.status?.phase === ProviderStatus.Ready;
 69	
 70	        if (isTarget) {
 71	          return isReady && provider.spec?.type === PROVIDER_TYPES.openshift;
 72	        }
 73	
 74	        return isReady;
 75	      }),
 76	    [isTarget, providers],
 77	  );
 78	
 79	  const providersListUrl = useMemo(
 80	    () =>
 81	      getResourceUrl({
 82	        namespace,
 83	        reference: ProviderModelRef,
 84	      }),
 85	    [namespace],
 86	  );
 87	
 88	  return (
 89	    <Select
 90	      id={id}
 91	      value={value}
 92	      status={status}
 93	      onSelect={onSelect}
 94	      placeholder={placeholder}
 95	      isDisabled={isDisabled}
 96	      testId={testId}
 97	      ref={ref}
 98	    >
 99	      <SelectList>
100	        {isEmpty(filteredProviders)
101	          ? (emptyState ?? (
102	              <EmptyState variant={EmptyStateVariant.xs}>
103	                <ForkliftTrans>
104	                  There are no providers in project <strong>{namespace}</strong>. Create one from
105	                  the{' '}
106	                  <ExternalLink
107	                    href={providersListUrl}
108	                    isInline
109	                    onClick={() => {
110	                      trackEvent(TELEMETRY_EVENTS.PROVIDER_CREATE_CLICKED, {
111	                        createSource: ProviderCreateSource.PlanWizard,
112	                      });
113	                    }}
114	                  >
115	                    Providers page
116	                  </ExternalLink>
117	                </ForkliftTrans>
118	              </EmptyState>
119	            ))
120	          : filteredProviders.map((provider) => {
121	              const providerName = getName(provider);
122	
123	              return (
124	                <SelectOption
125	                  icon={
126	                    <Icon size="lg">{getProviderTypeIcon(provider?.spec?.type, isDarkTheme)}</Icon>
127	                  }
128	                  key={providerName}
129	                  value={provider}
130	                >
131	                  {providerName}
132	                </SelectOption>
133	              );
134	            })}
135	      </SelectList>
136	    </Select>
137	  );
138	};
139	
140	export default forwardRef(ProviderSelect);

